const crypto = require('crypto');

function encryptAes256Hex(plaintext, passphrase) {
  if (typeof plaintext !== 'string') plaintext = String(plaintext);
  if (typeof passphrase !== 'string') passphrase = String(passphrase);

  const salt = crypto.randomBytes(16);
  const iv = crypto.randomBytes(16);

  const key = crypto.pbkdf2Sync(passphrase, salt, 100000, 32, 'sha256');

  const cipher = crypto.createCipheriv('aes-256-cbc', key, iv);
  const ciphertext = Buffer.concat([cipher.update(Buffer.from(plaintext, 'utf8')), cipher.final()]);

  // Format: salt(16) || iv(16) || ciphertext
  return Buffer.concat([salt, iv, ciphertext]).toString('hex');
}

module.exports = { encryptAes256Hex };

const crypto = require('crypto');

function decryptAes256HexCiphertext(hexCiphertext, passphrase) {
  if (typeof hexCiphertext !== 'string') throw new TypeError('hexCiphertext must be a string');
  if (typeof passphrase !== 'string') throw new TypeError('passphrase must be a string');

  const ciphertext = Buffer.from(hexCiphertext, 'hex');
  if (ciphertext.length < 16) throw new Error('Ciphertext too short');

  // Expected format: [16-byte IV][ciphertext...]
  const iv = ciphertext.subarray(0, 16);
  const enc = ciphertext.subarray(16);

  // Derive 32-byte key from passphrase using PBKDF2 (salt is fixed/implicit here).
  // If you have a different scheme, adjust accordingly.
  const salt = Buffer.alloc(16, 0); // fixed salt placeholder
  const key = crypto.pbkdf2Sync(passphrase, salt, 100000, 32, 'sha256');

  const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);
  const chunks = [decipher.update(enc), decipher.final()];
  return Buffer.concat(chunks).toString('utf8');
}

