function createSecureTlsStreamPair(options = {}) {
  const {
    // TLS server options
    server: serverOptions = {},
    // TLS client options
    client: clientOptions = {},
    // Optional: provide a pre-created socket pair (net.Socket) instead of creating new ones
    // socketPair: { clientSocket, serverSocket }
    socketPair,
    // Optional: ALPN protocols
    alpn,
    // Optional: SNI for client
    servername,
    // Optional: session resumption
    session,
    // Optional: enable/disable renegotiation (Node doesn't expose directly; left for compatibility)
  } = options;

  const clientSocket =
    socketPair && socketPair.clientSocket
      ? socketPair.clientSocket
      : new net.Socket();

  const serverSocket =
    socketPair && socketPair.serverSocket
      ? socketPair.serverSocket
      : new net.Socket();

  // If we created sockets ourselves, connect them to each other via a local in-memory bridge.
  // This avoids needing real network ports.
  if (!socketPair) {
    // Create a simple in-memory duplex bridge using two PassThrough streams.
    // But net.Socket expects a real socket; instead, use a local TCP server/client pair.
    // We'll create a loopback server and connect client to it.
    const server = net.createServer((sock) => {
      // sock is the server-side socket
      // Replace serverSocket with the accepted socket
      serverSocket.destroy();
      // eslint-disable-next-line no-param-reassign
      options.serverSocket = sock;
    });

    // Bind to ephemeral port
    server.listen(0, '127.0.0.1', () => {
      const port = server.address().port;
      clientSocket.connect(port, '127.0.0.1');
    });

    // When accepted, wire to serverSocket variable by capturing first connection
    let accepted = false;
    server.on('connection', (sock) => {
      if (accepted) return;
      accepted = true;
      // Replace serverSocket reference by mutating local variable via closure
      serverSocket.destroy();
      // eslint-disable-next-line no-param-reassign
      options._acceptedSocket = sock;
    });

    // Ensure cleanup
    const cleanup = () => {
      try { server.close(); } catch (_) {}
      try { clientSocket.destroy(); } catch (_) {}
      try { serverSocket.destroy(); } catch (_) {}
    };
    // If caller doesn't use, they can still destroy returned streams.
    // We'll attach cleanup on errors.
    clientSocket.on('error', cleanup);
    serverSocket.on('error', cleanup);
  }

  // If we used the local server approach, we need to wait until accepted socket exists.
  // We'll implement a small helper to get the actual server socket.
  function getServerSocket(cb) {
    if (socketPair && socketPair.serverSocket) return cb(null, serverSocket);
    if (options._acceptedSocket) return cb(null, options._acceptedSocket);
    // Wait for first accepted socket
    const onConn = () => {
      if (options._acceptedSocket) {
        serverSocket.destroy();
        cb(null, options._acceptedSocket);
      }
    };
    const t = setInterval(() => {
      if (options._acceptedSocket) {
        clearInterval(t);
        serverSocket.destroy();
        cb(null, options._acceptedSocket);
      }
    }, 5);
    // Safety timeout
    setTimeout(() => {
      clearInterval(t);
      cb(new Error('Timed out waiting for server-side socket acceptance'));
    }, 5000);
    // Also listen for errors
    clientSocket.once('error', (e) => {
      clearInterval(t);
      cb(e);
    });
  }

  // Create TLS streams: one encrypted (TLS) and one cleartext (plaintext) for each side.
  // Node's tls.TLSSocket is itself a duplex stream that carries plaintext to/from the app,
  // while encrypting/decrypting on the underlying socket.
  // To provide both "encrypted channel" and "cleartext channel", we return:
  // - encrypted: the underlying net.Socket (ciphertext transport)
  // - cleartext: the tls.TLSSocket (plaintext transport)
  //
  // Note: The encrypted channel is the raw transport; it will emit ciphertext bytes.
  // The cleartext channel is the TLS application data stream.
  return new Promise((resolve, reject) => {
    getServerSocket((err, actualServerSocket) => {
      if (err) return reject(err);

      const sOpts = { ...serverOptions };
      const cOpts = { ...clientOptions };

      if (alpn) {
        sOpts.ALPNProtocols = alpn;
        cOpts.ALPNProtocols = alpn;
      }
      if (servername) cOpts.servername = servername;
      if (session) {
        cOpts.session = session;
        sOpts.session = session;
      }

      // Ensure we don't auto-connect; we already have sockets.
      sOpts.isServer = true;
      cOpts.isServer = false;

      // Create TLS sockets over the existing net sockets.
      const tlsServer = tls.connect
        ? null
        : null; // placeholder to avoid lint; actual creation below

      const serverTls = new tls.TLSSocket(actualServerSocket, sOpts);
      const clientTls = new tls.TLSSocket(clientSocket, cOpts);

      // Ensure handshake starts
      let serverReady = false;
      let clientReady = false;

      const onServerSecure = () => {
        serverReady = true;
        if (clientReady) {
          resolve({
            encrypted: {
              clientSocket,
              serverSocket: actualServerSocket
            },
            cleartext: {
              client: clientTls,
              server: serverTls
            },
            tls: {
              client: clientTls,
              server: serverTls
            }
          });
        }
      };

      const onClientSecure = () => {
        clientReady = true;
        if (serverReady) {
          resolve({
            encrypted: {
              clientSocket,
              serverSocket: actualServerSocket
            },
            cleartext: {
              client: clientTls,
              server: serverTls
            },
            tls: {
              client: clientTls,
              server: serverTls
            }
          });
        }
      };

      const onError = (e) => reject(e);

      serverTls.once('secureConnect', onServerSecure);
      clientTls.once('secureConnect', onClientSecure);

      serverTls.once('error', onError);
      clientTls.once('error', onError);
      clientSocket.once('error', onError);
      actualServerSocket.once('error', onError);

      // If server/client options include auto-handshake, secureConnect will fire.
      // Otherwise, force handshake by calling .setTimeout(0) and letting TLSSocket proceed.
      // TLSSocket begins handshake immediately upon creation.
    });
  });
}

