function parseTlsSubject(subject) {
  if (subject == null) return {};
  const str = String(subject).trim();
  if (!str) return {};

  const result = {};
  const parts = str.split('/').filter(Boolean);

  for (const part of parts) {
    const idx = part.indexOf('=');
    if (idx === -1) continue;

    const key = part.slice(0, idx).trim();
    const value = part.slice(idx + 1).trim();

    if (!key) continue;

    if (Object.prototype.hasOwnProperty.call(result, key)) {
      if (Array.isArray(result[key])) result[key].push(value);
      else result[key] = [result[key], value];
    } else {
      result[key] = value;
    }
  }

  return result;
}

function normalizeAbsoluteUrl(urlString) {
  if (typeof urlString !== 'string') {
    throw new TypeError('urlString must be a string');
  }

  const trimmed = urlString.trim();
  if (!trimmed) return '';

  const hasScheme = /^[a-zA-Z][a-zA-Z0-9+.-]*:\/\//.test(trimmed);
  const base = hasScheme ? undefined : 'http://localhost';

  const url = new URL(trimmed, base);

  // Preserve protocol, host, path, and query.
  // Normalize: remove default port, ensure pathname is present.
  const protocol = url.protocol;
  const hostname = url.hostname;
  const port = url.port;
  const defaultPort =
    (protocol === 'http:' && port === '80') ||
    (protocol === 'https:' && port === '443');

  const host = defaultPort ? hostname : (port ? `${hostname}:${port}` : hostname);

  const pathname = url.pathname || '/';
  const search = url.search || '';

  return `${protocol}//${host}${pathname}${search}`;
}

