class PropSyncComponent extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      derivedFromProps: this.getDerivedStateFromProps(props),
    };
  }

  getDerivedStateFromProps(props) {
    // Customize this mapping as needed
    return {
      value: props.value,
      other: props.other,
    };
  }

  componentDidUpdate(prevProps) {
    if (
      prevProps.value !== this.props.value ||
      prevProps.other !== this.props.other
    ) {
      this.setState({
        derivedFromProps: this.getDerivedStateFromProps(this.props),
      });
    }
  }

  render() {
    const { derivedFromProps } = this.state;
    return (
      <div>
        <div>Value: {derivedFromProps.value}</div>
        <div>Other: {derivedFromProps.other}</div>
      </div>
    );
  }
}

