import { toASCII, toUnicode } from 'punycode/';

function convertIDNToPunycode(domain) {
  try {
    const parts = domain.split('.');
    const punycodeparts = parts.map(part => toASCII(part));
    return punycodeparts.join('.');
  } catch (error) {
    console.error('Error converting domain to Punycode:', error.message);
    return null;
  }
}

function convertPunycodeToIDN(domain) {
  try {
    const parts = domain.split('.');
    const idnParts = parts.map(part => toUnicode(part));
    return idnParts.join('.');
  } catch (error) {
    console.error('Error converting domain from Punycode:', error.message);
    return null;
  }
}

