import crypto from 'crypto';

function encryptAES256(plaintext, passphrase) {
  // Derive a 256-bit key from the passphrase using PBKDF2
  const salt = crypto.randomBytes(16);
  const key = crypto.pbkdf2Sync(passphrase, salt, 100000, 32, 'sha256');

  // Generate a random 128-bit IV
  const iv = crypto.randomBytes(16);

  // Create cipher
  const cipher = crypto.createCipheriv('aes-256-cbc', key, iv);

  // Encrypt the plaintext
  let encrypted = cipher.update(plaintext, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  // Combine salt, IV, and encrypted data
  const result = salt.toString('hex') + iv.toString('hex') + encrypted;

  return result;
}

function decryptAES256(encryptedHex, passphrase) {
  // Extract salt, IV, and encrypted data
  const salt = Buffer.from(encryptedHex.slice(0, 32), 'hex');
  const iv = Buffer.from(encryptedHex.slice(32, 64), 'hex');
  const encrypted = encryptedHex.slice(64);

  // Derive the same key from the passphrase and salt
  const key = crypto.pbkdf2Sync(passphrase, salt, 100000, 32, 'sha256');

  // Create decipher
  const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);

  // Decrypt the data
  let decrypted = decipher.update(encrypted, 'hex', 'utf8');
  decrypted += decipher.final('utf8');

  return decrypted;
}

